  "inlineSchema": "// ── Intent Graph Prisma Schema ────────────────────────────────────────────────\n// RTMN Commerce Memory - Core intent tracking models\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ── Core Intent Model ─────────────────────────────────────────────────────────\n\nmodel Intent {\n  id          String   @id @default(cuid())\n  userId      String\n  merchantId  String? // Associated merchant (for demand aggregation)\n  appType     String // hotel_ota, restaurant, retail, hotel_guest\n  category    String // TRAVEL, DINING, RETAIL, HOTEL_SERVICE, GENERAL\n  intentKey   String // e.g., \"hotel_goa_weekend\", \"restaurant_biryani\"\n  intentQuery String? // Original search query\n  metadata    Json? // Additional structured data\n  confidence  Decimal  @db.Decimal(3, 2) // 0.00 to 1.00\n  status      String   @default(\"ACTIVE\") // ACTIVE, DORMANT, FULFILLED, EXPIRED\n  firstSeenAt DateTime @default(now())\n  lastSeenAt  DateTime @updatedAt\n\n  // Relations\n  signals        IntentSignal[]\n  dormantIntents DormantIntent[]\n  sequences      IntentSequence[]\n\n  // Indexes\n  @@unique([userId, appType, intentKey])\n  @@index([userId, status])\n  @@index([status, lastSeenAt])\n  @@index([category, status])\n  @@index([appType, category])\n  @@index([merchantId, category])\n}\n\n// ── Intent Signal ─────────────────────────────────────────────────────────────\n\nmodel IntentSignal {\n  id         String   @id @default(cuid())\n  intentId   String\n  eventType  String // search, view, wishlist, cart_add, hold, checkout_start, fulfilled, abandoned\n  weight     Decimal  @db.Decimal(3, 2)\n  data       Json? // Additional event data\n  capturedAt DateTime @default(now())\n\n  // Relation\n  intent Intent @relation(fields: [intentId], references: [id], onDelete: Cascade)\n\n  // Indexes\n  @@index([intentId])\n  @@index([eventType, capturedAt])\n  @@index([intentId, capturedAt])\n}\n\n// ── Dormant Intent ────────────────────────────────────────────────────────────\n\nmodel DormantIntent {\n  id             String    @id @default(cuid())\n  intentId       String\n  userId         String\n  appType        String\n  category       String\n  intentKey      String\n  dormancyScore  Decimal   @db.Decimal(4, 3) // 0.000 to 1.000\n  revivalScore   Decimal   @db.Decimal(4, 3) // 0.000 to 1.000\n  daysDormant    Int\n  lastNudgeSent  DateTime?\n  nudgeCount     Int       @default(0)\n  idealRevivalAt DateTime?\n  status         String    @default(\"active\") // active, paused, revived\n  revivedAt      DateTime?\n\n  // Relation\n  intent Intent @relation(fields: [intentId], references: [id], onDelete: Cascade)\n\n  // Indexes\n  @@unique([userId, appType, intentKey])\n  @@index([userId, status])\n  @@index([status, revivalScore])\n  @@index([idealRevivalAt])\n}\n\n// ── Intent Sequence ───────────────────────────────────────────────────────────\n\nmodel IntentSequence {\n  id            String   @id @default(cuid())\n  intentId      String\n  userId        String\n  eventType     String\n  sequenceOrder Int\n  durationMs    Int? // Time from previous event\n  occurredAt    DateTime @default(now())\n\n  // Relation\n  intent Intent @relation(fields: [intentId], references: [id], onDelete: Cascade)\n\n  // Indexes\n  @@index([intentId, sequenceOrder])\n  @@index([userId, occurredAt])\n}\n\n// ── Cross-App Intent Profile ──────────────────────────────────────────────────\n\nmodel CrossAppIntentProfile {\n  id                 String   @id @default(cuid())\n  userId             String   @unique\n  travelIntentCount  Int      @default(0)\n  diningIntentCount  Int      @default(0)\n  retailIntentCount  Int      @default(0)\n  dormantTravelCount Int      @default(0)\n  dormantDiningCount Int      @default(0)\n  dormantRetailCount Int      @default(0)\n  totalConversions   Int      @default(0)\n  travelAffinity     Int      @default(50) // 0-100 scale\n  diningAffinity     Int      @default(50)\n  retailAffinity     Int      @default(50)\n  updatedAt          DateTime @updatedAt\n\n  // Indexes\n  @@index([travelAffinity])\n  @@index([diningAffinity])\n  @@index([totalConversions])\n}\n\n// ── Merchant Demand Signals ───────────────────────────────────────────────────\n\nmodel MerchantDemandSignal {\n  id                  String   @id @default(cuid())\n  merchantId          String\n  category            String\n  demandCount         Int      @default(0)\n  unmetDemandPct      Decimal  @db.Decimal(5, 2) // Percentage of intents not fulfilled\n  avgPriceExpectation Int?\n  topCities           String[]\n  trend               String   @default(\"stable\") // rising, stable, declining\n  lastAggregated      DateTime @default(now())\n\n  // Indexes\n  @@unique([merchantId, category])\n  @@index([category, trend])\n  @@index([demandCount])\n}\n\n// ── Procurement Signals ───────────────────────────────────────────────────────\n\nmodel ProcurementSignal {\n  id         String   @id @default(cuid())\n  category   String\n  demandGaps String[] // Products high demand, low supply\n  createdAt  DateTime @default(now())\n  updatedAt  DateTime @updatedAt\n\n  @@index([category])\n}\n\n// ── Nudge Model ──────────────────────────────────────────────────────────────\n\nmodel Nudge {\n  id              String    @id @default(cuid())\n  dormantIntentId String\n  userId          String\n  channel         String // push, email, sms, in_app\n  message         String\n  status          String    @default(\"pending\") // pending, sent, delivered, clicked, converted, failed\n  sentAt          DateTime?\n  deliveredAt     DateTime?\n  clickedAt       DateTime?\n  convertedAt     DateTime?\n  error           String?\n  createdAt       DateTime  @default(now())\n\n  // Indexes\n  @@index([dormantIntentId])\n  @@index([userId, status])\n  @@index([status, createdAt])\n  @@index([channel, status])\n}\n\n// ── Nudge Schedule ────────────────────────────────────────────────────────────\n\nmodel NudgeSchedule {\n  id              String   @id @default(cuid())\n  userId          String\n  category        String // TRAVEL, DINING, RETAIL\n  triggerType     String // scheduled, price_drop, return_user, seasonality, offer_match\n  channel         String // push, email, sms, in_app\n  minRevivalScore Decimal  @default(0.3) @db.Decimal(4, 3)\n  active          Boolean  @default(true)\n  createdAt       DateTime @default(now())\n  updatedAt       DateTime @updatedAt\n\n  @@index([userId, active])\n  @@index([category, triggerType])\n}\n",
  "inlineSchemaHash": "82ad3d85b10cd0fe4f371969324c3554a9d227a083c6ec8d5df0e294709c7108",
